import { useRef, useState } from 'react';

export function TiltedCard({
  children,
  maxTilt = 15,
  perspective = 1000,
  className = ""
}) {
  const ref = useRef(null);
  const [tilt, setTilt] = useState({ x: 0, y: 0 });

  const handleMouseMove = (e) => {
    if (!ref.current) return;
    const { left, top, width, height } = ref.current.getBoundingClientRect();
    const x = (e.clientX - left) / width; // 0 to 1
    const y = (e.clientY - top) / height; // 0 to 1

    // Convert scale coordinates to angle limits
    const tiltX = (y - 0.5) * -maxTilt;
    const tiltY = (x - 0.5) * maxTilt;
    setTilt({ x: tiltX, y: tiltY });
  };

  const handleMouseLeave = () => {
    setTilt({ x: 0, y: 0 });
  };

  return (
    <div
      ref={ref}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      style={{
        transform: `perspective(${perspective}px) rotateX(${tilt.x}deg) rotateY(${tilt.y}deg)`,
        transition: 'transform 0.1s cubic-bezier(0.25, 1, 0.5, 1)',
        transformStyle: 'preserve-3d'
      }}
      className={`inline-block overflow-hidden rounded-2xl border border-border bg-card shadow-lg ${className}`}
    >
      <div style={{ transform: 'translateZ(20px)' }} className="p-6">
        {children}
      </div>
    </div>
  );
}

import { useState } from 'react';

export function TrueFocusText({
  text = "Bring visual focus to key messages dynamically.",
  className = ""
}) {
  const [focusedIndex, setFocusedIndex] = useState(null);
  const words = text.split(" ");

  return (
    <div className={`flex flex-wrap gap-x-3 gap-y-1.5 text-2xl font-bold tracking-tight select-none ${className}`}>
      {words.map((word, idx) => {
        const isFocused = focusedIndex === idx;
        const hasHovered = focusedIndex !== null;
        let blurStyle = {};

        if (hasHovered) {
          blurStyle = isFocused 
            ? { filter: 'blur(0px)', color: 'var(--primary)', scale: '1.05' }
            : { filter: 'blur(3px)', opacity: 0.45, scale: '0.98' };
        }

        return (
          <span
            key={idx}
            onMouseEnter={() => setFocusedIndex(idx)}
            onMouseLeave={() => setFocusedIndex(null)}
            style={{
              transition: 'filter 0.2s ease, opacity 0.2s ease, color 0.2s ease, transform 0.2s ease',
              display: 'inline-block',
              transformOrigin: 'center center',
              ...blurStyle
            }}
            className="cursor-pointer text-foreground"
          >
            {word}
          </span>
        );
      })}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Calendar, Clock, Globe } from 'lucide-react';

export function GlassTimeCard({ timezone = "UTC" }) {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const timeString = time.toLocaleTimeString('en-US', {
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: true,
    timeZone: timezone
  });

  const dateString = time.toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    year: 'numeric',
    timeZone: timezone
  });

  return (
    <div className="w-full max-w-sm overflow-hidden rounded-2xl border border-white/10 bg-neutral-900/40 p-6 text-white backdrop-blur-lg shadow-2xl">
      <div className="flex items-center justify-between border-b border-white/10 pb-4">
        <div className="flex items-center gap-2">
          <Globe className="h-4 w-4 text-primary" />
          <span className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">
            Timezone: {timezone}
          </span>
        </div>
        <span className="h-2.5 w-2.5 rounded-full bg-emerald-500 animate-pulse" />
      </div>
      <div className="py-6 text-center">
        <div className="inline-flex items-center justify-center gap-2.5 text-4xl font-extrabold tracking-tight">
          <Clock className="h-8 w-8 text-primary" />
          <span className="font-mono">{timeString}</span>
        </div>
      </div>
      <div className="flex items-center justify-center gap-2 border-t border-white/10 pt-4 text-sm text-muted-foreground">
        <Calendar className="h-4 w-4" />
        <span>{dateString}</span>
      </div>
    </div>
  );
}

