    { name: "Team", icon: <Users className="h-5 w-5" /> },
    { name: "Analytics", icon: <BarChart2 className="h-5 w-5" /> },
    { name: "Documents", icon: <BookOpen className="h-5 w-5" /> },
    { name: "Settings", icon: <Settings className="h-5 w-5" /> },
  ];

  return (
    <aside 
      style={{ width: isCollapsed ? '72px' : '260px' }}
      className="flex h-screen flex-col border-r border-border bg-card text-card-foreground transition-all duration-200"
    >
      {/* Sidebar Header */}
      <div className="flex h-16 items-center justify-between px-4 border-b border-border">
